import React, { useEffect } from "react";
import axios from "axios";
import requests from "../requests";
import useStatePromise from "use-state-promise";
import Slider from "react-slick";
import { useMediaQuery } from "react-responsive";

import { CurrentSeasonStore } from "../store/CurrentSeasonStore";
import { useHistory } from "react-router";

function SeasonsHolder({ id }) {
  const isBigScreen = useMediaQuery({ query: "(min-width: 789px)" });

  const settings = {
    dots: false,
    speed: 500,
    slidesToShow: 4,
    slidesToScroll: 4,
    initialSlide: 0,
    variableWidth: true,
    adaptiveHeight: false,
    infinite: false,
    focusOnSelect: true,
    arrows: true,
  };
  const history = useHistory();

  const API_KEY = "20108f1c4ed38f7457c479849a9999cc";
  const [currentTvShow, setCurrentTvShowPromise, setCurrentTvShow] =
    useStatePromise({});

  const [seasons, setSeasonsPromise, setSeasons] = useStatePromise([]);

  // check if  a movie or a tv show
  useEffect(() => {
    async function fetchIt() {
      const res = await axios.get(
        `https://api.themoviedb.org/3/tv/${id}?api_key=${API_KEY}`
      );
      if (res.success !== false) {
        setCurrentTvShowPromise(() => {
          setCurrentTvShow({ ...res.data });
          return currentTvShow;
        }).then((currentTvShow) => {
          setSeasons([...currentTvShow.seasons]);
        });
      }
    }
    fetchIt();
  }, [id]);

  // add event listener to seasonCard so when u click it chnage the current season value
  const chnageCurrentSeason = (e) => {
    const seasonName = e.target.dataset.seasonname;
    const seasonNumber = e.target.dataset.seasonnumber;
    const poster_path = e.target.dataset.seasonposterpath;

    CurrentSeasonStore.update((s) => {
      s.tv_name = currentTvShow.name || currentTvShow.original_name;
      s.season_name = seasonName;
      s.id = id;
      s.season_poster_path = poster_path;
      s.season_number = seasonNumber;
    });

    console.log(poster_path);

    return history.push(`/tv/${id}/season/${seasonNumber}/episodes`);
  };

  return (
    <div className="seasonsHolder">
      <h1>Seasons</h1>

      {isBigScreen ? (
        <Slider {...settings}>
          {seasons.map((season, key) =>
            season.episode_count >= 1 &&
            season.season_number >= 1 &&
            season.poster_path !== null ? (
              <div className="season_holder MovieCard" id="seasonCard">
                <img
                  src={requests.image_api + season.poster_path}
                  id={key}
                  alt={season.season_number}
                  data-seasonnumber={season.season_number}
                  data-seasonname={season.name}
                  data-seasonposterpath={season.poster_path}
                  onClick={chnageCurrentSeason}
                />
                <h4 className="voteAvarage">
                  <span>{season.name}</span>
                </h4>
              </div>
            ) : (
              ""
            )
          )}
        </Slider>
      ) : (
        <div className="row__posters">
          {seasons.map((season, key) =>
            season.episode_count >= 1 &&
            season.season_number >= 1 &&
            season.poster_path !== null ? (
              <div className="season_holder MovieCard" id="seasonCard">
                <img
                  src={requests.image_api + season.poster_path}
                  id={key}
                  alt={season.season_number}
                  data-seasonnumber={season.season_number}
                  data-seasonname={season.name}
                  data-seasonposterpath={season.poster_path}
                  onClick={chnageCurrentSeason}
                />

                <h4 className="voteAvarage">
                  <span>{season.name}</span>
                </h4>
              </div>
            ) : (
              ""
            )
          )}
        </div>
      )}
    </div>
  );
}

export default SeasonsHolder;
