import React, { useEffect } from "react";
import SearchBar from "./SearchBar";
import WatchListButton from "./WatchListButton";
import { useMediaQuery } from "react-responsive";
import { useAuth0 } from "@auth0/auth0-react";
import { Link } from "react-router-dom";

function MenuBox({
  setMovieQuery,
  movies,
  setMovies,
  showSearchMenu,
  setShowSearchMenu,
  watchListLen,
  setIsLoading,
}) {
  const isBigScreen = useMediaQuery({ query: "(min-width: 564px)" });
  const { loginWithRedirect, user, isAuthenticated, isLoading } = useAuth0();
  useEffect(() => {
    setIsLoading(isLoading);
  }, [isLoading]);
  return (
    <div className="MenuBox" id="MenuBox">
      {isBigScreen && (
        <SearchBar
          Class="SearchBar"
          setMovieQuery={setMovieQuery}
          movies={movies}
          setMovies={setMovies}
          showSearchMenu={showSearchMenu}
          setShowSearchMenu={setShowSearchMenu}
        />
      )}
      {!isAuthenticated && !isLoading && (
        <button
          className="loginButton WatchListButton"
          onClick={() => loginWithRedirect()}
        >
          login
        </button>
      )}
      <WatchListButton watchListLen={watchListLen} />
      {isAuthenticated && (
        <Link to="/account" className="accountLink">
          <img src={user?.picture} className="userAvatar"></img>
        </Link>
      )}
    </div>
  );
}

export default MenuBox;
